    int n = dist.length;
    double[][] dp = new double[n + 1][n + 1];

    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= n; j++) {
            dp[i][j] = 1e6;
        }
    }
    dp[0][0] = 0;
    for (int i = 1; i <= n; i++) {
        dp[i][0] = Math.ceil(dp[i - 1][0] + (double) dist[i - 1] / speed) - 1;
    }

